/**
 * 파일 역할:
 *   Vite 클라이언트 환경에 대한 전역 타입 선언 파일(ambient declaration).
 *   런타임 코드는 전혀 없으며, TypeScript 컴파일러에게 Vite가 주입하는
 *   타입 정보(import.meta.env 등)와 프로젝트 전용 환경변수의 형태를 알려준다.
 *
 * 핵심 책임:
 *   - Vite가 제공하는 클라이언트 타입(예: import.meta.env, 에셋 import 등)을 참조.
 *   - 이 프로젝트에서 사용하는 커스텀 환경변수(VITE_*)의 타입을 정의하여
 *     코드 전반에서 import.meta.env.VITE_... 사용 시 자동완성과 타입 검사 지원.
 *
 * 주요 export:
 *   없음(이 파일은 .d.ts 선언 파일로, 전역 인터페이스만 확장/병합한다).
 *
 * ──────────────────────────────────────────────────────────────────────────
 * [초보자를 위한 배경 설명]
 *
 * ▸ .d.ts 파일이란?
 *   - "d"는 declaration(선언)의 약자다. 확장자가 .d.ts 인 파일은
 *     "타입 선언 전용 파일"이다. 즉 실제로 실행되는 코드(함수 호출, 변수 대입 등)는
 *     한 줄도 들어가지 않고, 오직 "이런 값은 이런 타입이다"라는 정보만 담는다.
 *   - 그래서 이 파일을 아무리 봐도 화면에 무언가를 그리거나 계산하는 동작은 없다.
 *     이 파일의 목적은 오로지 TypeScript 컴파일러(타입 검사기)에게 정보를 주는 것이다.
 *
 * ▸ "ambient(앰비언트) 선언"이란?
 *   - 특정 모듈로 import 하지 않아도, 프로젝트 어디서나 자동으로 적용되는
 *     "전역(global) 타입 선언"을 뜻한다. 이 파일에 적힌 타입은 별도 import 없이
 *     앱의 모든 파일에서 자동으로 인식된다.
 *
 * ▸ Vite란?
 *   - 이 프로젝트가 사용하는 "개발 서버 + 번들러(빌드 도구)"다.
 *     코드를 브라우저가 이해할 수 있는 형태로 묶어주고, 개발 중에는 빠른 미리보기를 제공한다.
 *
 * ▸ 환경변수(environment variable)란?
 *   - API 주소나 비밀 키처럼, 코드에 직접 박아두기 곤란한 "설정 값"을 외부에서 주입하는 방법.
 *   - 보통 프로젝트 루트의 .env 파일에 `VITE_SUPABASE_URL=...` 같은 형태로 적어둔다.
 *   - 코드에서는 import.meta.env.VITE_SUPABASE_URL 처럼 읽어서 사용한다.
 *
 * 주의: 이 파일의 "코드"는 전부 타입 선언이라 실행 동작이 없다. 그래도 매우 중요하다.
 *       이 파일이 없으면 import.meta.env.VITE_... 를 쓸 때 자동완성이 안 되고,
 *       타입 검사기가 "그런 속성은 모른다"고 경고할 수 있다.
 * ──────────────────────────────────────────────────────────────────────────
 */

// /// <reference ... /> 는 "트리플 슬래시 지시어(triple-slash directive)"라는
// TypeScript 전용 특수 주석이다. 일반 주석처럼 보이지만, 컴파일러에게 보내는 명령이다.
//   ▸ 의미: "vite/client" 라는 패키지가 제공하는 타입 정의를 이 파일에 포함시켜라.
//   ▸ 효과: Vite가 기본 제공하는 타입들(import.meta.env의 기본 속성,
//           이미지/CSS 같은 에셋을 import 할 때의 타입 등)을 사용할 수 있게 된다.
// 주의: 슬래시 3개(///)와 정확한 형식이 지켜져야만 지시어로 인식된다.
//       일반 주석(//)으로 착각해 한 칸 지우거나 형식을 바꾸면 타입이 깨질 수 있다.
/// <reference types="vite/client" />

// 앱에서 사용하는 환경변수(import.meta.env)의 타입 정의.
// Vite는 VITE_ 접두어가 붙은 변수만 클라이언트 번들에 노출한다.
//
// [개념] interface(인터페이스)란?
//   - TypeScript에서 "객체가 어떤 속성과 타입을 가져야 하는지"를 정의하는 설계도다.
//   - 여기서는 import.meta.env 라는 객체가 어떤 환경변수를 담고 있는지를 적는다.
// [개념] "인터페이스 병합(declaration merging)"
//   - 같은 이름의 interface 를 여러 곳에서 선언하면 TypeScript가 자동으로 하나로 합친다.
//   - 'vite/client' 안에도 ImportMetaEnv 인터페이스가 이미 있는데,
//     여기서 같은 이름으로 다시 선언하면 우리 환경변수가 거기에 "추가"된다.
//   - 즉 이 코드는 기존 타입을 덮어쓰는 게 아니라 우리 변수만 보태는 것이다.
//
// 주의: .env 파일에서 변수 이름은 반드시 VITE_ 로 시작해야 브라우저 코드에서 읽힌다.
//       (예: SUPABASE_URL 로 적으면 보안상 클라이언트에 노출되지 않아 undefined 가 된다.)
interface ImportMetaEnv {
  // Supabase 프로젝트 URL (백엔드 엔드포인트)
  //   ▸ Supabase는 데이터베이스/인증/스토리지를 제공하는 백엔드 서비스(BaaS)다.
  //   ▸ 이 URL이 우리 앱이 데이터를 주고받을 서버 주소가 된다.
  //   ▸ readonly: "읽기 전용"이라는 표시. 코드에서 이 값을 다시 대입해 바꿀 수 없게 막는다.
  //     (환경변수는 앱 실행 중 바뀌면 안 되는 값이므로 읽기 전용이 자연스럽다.)
  //   ▸ : string  은 "이 값의 타입은 문자열"이라는 뜻이다.
  readonly VITE_SUPABASE_URL: string;
  // Supabase anon(공개) 키 — 클라이언트에서 RLS 정책 하에 사용되는 공개 키
  //   ▸ anon = anonymous(익명) 키. 브라우저(클라이언트)에 노출되어도 되는 "공개용" 키다.
  //   ▸ RLS(Row Level Security, 행 수준 보안): 데이터베이스가 "이 사용자는 이 행에만
  //     접근 가능"이라고 행 단위로 권한을 통제하는 보안 기능. 그래서 공개 키여도
  //     RLS 규칙이 막아주는 데이터에는 함부로 접근할 수 없다.
  //   ▸ 주의: 진짜 비밀 키(service_role 등)는 절대 VITE_ 로 클라이언트에 넣으면 안 된다.
  //          VITE_ 변수는 빌드된 자바스크립트에 그대로 박혀 누구나 볼 수 있기 때문이다.
  readonly VITE_SUPABASE_ANON_KEY: string;
}

// import.meta.env가 위에서 정의한 ImportMetaEnv 타입을 갖도록 ImportMeta를 확장.
//
// [개념] import.meta 란?
//   - 자바스크립트 모듈이 자기 자신에 대한 메타 정보(예: 환경변수)를 담아두는 특수 객체다.
//   - Vite는 여기에 .env 라는 속성을 붙여 환경변수를 제공한다 → import.meta.env
// 이 ImportMeta 인터페이스 역시 위에서 설명한 "인터페이스 병합"으로 동작한다.
//   ▸ 즉 import.meta 객체에 env 라는 속성이 있고, 그 타입이 우리가 정의한
//     ImportMetaEnv 라는 것을 컴파일러에게 알려준다.
//   ▸ 결과: 코드에서 import.meta.env. 까지 입력하면 VITE_SUPABASE_URL 등이
//     자동완성으로 뜨고, 오타를 내면 타입 검사기가 즉시 잡아준다.
interface ImportMeta {
  // env 속성의 타입은 위에서 만든 ImportMetaEnv (역시 읽기 전용).
  readonly env: ImportMetaEnv;
}
